          <div class="studio"><section class="panel"><p class="eyebrow">Application pack</p><h2>{{ selectedJob.company }}</h2><p>{{ selectedJob.title }}</p><div class="score-line"><b :class="['fit', fitClass(selectedJob.score)]">{{ selectedJob.score }}</b><span>Illustrative fit score</span></div><hr><p><strong>Included evidence</strong></p><ul class="check-list"><li v-for="claim in editableClaims" :key="claim">{{ claim }}</li></ul><button class="secondary" @click="go('readiness')">Open readiness review</button></section><section class="panel compose"><p class="eyebrow">Recruiter message</p><h2>Human-edited application draft</h2><label>Subject line<input v-model="composeSubject" /></label><label>Message<textarea v-model="composeMessage" rows="10" /></label><div class="actions"><button class="primary" @click="composeReviewed = true">Mark ready for human review</button><button class="secondary" @click="go('track')">Open submission checklist →</button></div><p v-if="composeReviewed" class="success">✓ The fictional draft is ready for a human to review. This demo cannot submit it.</p></section></div>
